export type Cell = [number, number];

const coordKey = (x: number, y: number): string => `${x},${y}`;

const forEachNeighbor = (
  x: number,
  y: number,
  visit: (nx: number, ny: number) => void,
): void => {
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      visit(x + dx, y + dy);
    }
  }
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => coordKey(x, y)));

  const countLiveNeighbors = (x: number, y: number): number => {
    let count = 0;
    forEachNeighbor(x, y, (nx, ny) => {
      if (liveSet.has(coordKey(nx, ny))) count++;
    });
    return count;
  };

  const survivors: Cell[] = cells.filter(([x, y]) => {
    const n = countLiveNeighbors(x, y);
    return n === 2 || n === 3;
  });

  const births: Cell[] = [];
  const considered = new Set<string>(liveSet);
  for (const [x, y] of cells) {
    forEachNeighbor(x, y, (nx, ny) => {
      const k = coordKey(nx, ny);
      if (considered.has(k)) return;
      considered.add(k);
      if (countLiveNeighbors(nx, ny) === 3) births.push([nx, ny]);
    });
  }

  return [...survivors, ...births];
}
